17	function normalizeIdArray(value, fallbackValue = null) {
18	  const source = Array.isArray(value) ? value : (value ? [value] : []);
19	  if (fallbackValue) source.push(fallbackValue);
20	  return [...new Set(source.map(id => Number(id)).filter(Boolean))];
21	}
