492	async function enrichLicensingStatusWithReplyStats(rows, currentUserId) {
493	  if (!rows?.length) return rows || [];
494	
495	  const statusIds = rows.map(r => (r.get ? r.get({ plain: true }) : r).id).filter(Boolean);
496	  const statsMap = {};
497	  const userTaggedStatusIds = new Set();
498	
499	  if (sql.licensingFeedbackReply && statusIds.length) {
500	    const replyStats = await sql.licensingFeedbackReply.findAll({
501	      attributes: [
502	        'licensing_status_id_fk',
503	        [Sequelize.fn('COUNT', Sequelize.col('id')), 'reply_count'],
504	        [Sequelize.fn('MAX', Sequelize.col('created_at')), 'latest_reply_at']
505	      ],
506	      where: { licensing_status_id_fk: { [Op.in]: statusIds } },
507	      group: ['licensing_status_id_fk'],
508	      raw: true
509	    });
510	
511	    replyStats.forEach(s => {
512	      statsMap[s.licensing_status_id_fk] = s;
513	    });
514	
515	    if (currentUserId) {
516	      const replies = await sql.licensingFeedbackReply.findAll({
517	        attributes: ['licensing_status_id_fk', 'tagged_user_ids'],
518	        where: { licensing_status_id_fk: { [Op.in]: statusIds } },
519	        raw: true
520	      });
521	
522	      replies.forEach(r => {
523	        const taggedIds = Array.isArray(r.tagged_user_ids) ? r.tagged_user_ids : [];
524	        if (taggedIds.map(Number).includes(Number(currentUserId))) {
525	          userTaggedStatusIds.add(r.licensing_status_id_fk);
526	        }
527	      });
528	    }
529	  }
530	
531	  return rows.map(row => {
532	    const plain = row.get ? row.get({ plain: true }) : { ...row };
533	    const stats = statsMap[plain.id] || {};
534	    plain.reply_count = Number(stats.reply_count) || 0;
535	    plain.latest_reply_at = stats.latest_reply_at || null;
536	    plain.has_reply_tagging_current_user = userTaggedStatusIds.has(plain.id);
537	    return plain;
538	  });
539	}
