339	
340	    if (this.form.invalid) {
341	      // Check specifically for date validation
342	      if (!this.form.value.dateModifiedControler) {
343	        this._snakcbar.open('Date is required. Please select a date.', 'close');
344	      } else if (!this.form.value.StatusController) {
