357	
358	    this.isSaving = true;
359	    try {
360	      const attachmentsPayload = await this.uploadPendingAttachments();
361	      const selectedAssignees = Array.isArray(this.form.value.AssigneeController)
362	        ? this.form.value.AssigneeController
