402	  async uploadPendingAttachments(): Promise<AttachmentPayload[]> {
403	    const uploads: AttachmentPayload[] = [];
404	
405	    for (const attachment of this.attachments) {
406	      if (attachment.link) {
407	        uploads.push({
408	          name: attachment.name,
409	          link: attachment.link,
410	          type: attachment.type,
411	          size: attachment.size
412	        });
413	        continue;
414	      }
415	
416	      attachment.status = 'uploading';
417	      const storageName = this.buildStorageFileName(attachment.file);
418	      const contentType = attachment.type || 'application/octet-stream';
419	      await this.helper.saveToDigitalOceanAndDB(storageName, contentType, attachment.file);
420	      const link = this.helper.buildPublicUrl(storageName);
421	      attachment.link = link;
422	      attachment.status = 'uploaded';
423	      uploads.push({
424	        name: attachment.name,
425	        link,
426	        type: attachment.type,
427	        size: attachment.size
428	      });
429	    }
430	
431	    return uploads;
432	  }
