ItemDetail.BulkAddLicensingStatus = async (req, result) => {
  const userInfo = await getUserInfo(req.headers.authorization);
  try {
    const feedbackList = Array.isArray(req.body) ? req.body : [];
    const saved = [];
    const failures = [];

    for (let index = 0; index < feedbackList.length; index++) {
      const feedback = feedbackList[index];
      const body = { ...feedback };

      // L1: reject empty/unknown status values before attempting to persist.
      const statusError = validateLicensingStatus(body.status);
      if (statusError) {
        failures.push({ index, itemheader_id_fk: body.itemheader_id_fk, status: body.status, message: statusError });
        continue;
      }

      try {
        body.moduser = userInfo.name;
        body.assignor_id = userInfo.user_id ?? userInfo.id;
        body.attachments = Array.isArray(body.attachments) ? body.attachments : [];
        body.assignee_ids = normalizeIdArray(body.assignee_ids, body.assignee_id);
        body.assignee_id = body.assignee_ids[0] || null;

        const data = await sql.licensingStatus.create(body);
        if (!data) {
          failures.push({ index, itemheader_id_fk: body.itemheader_id_fk, status: body.status, message: 'Failed to create licensing status' });
          continue;
        }

        const mapData = {
          actionDate: body.date,
          status: body.status,
          feedback: body.feedback,
          pop_comments: body.pop_comments,
          from: body.from,
          username: body.moduser,
          approval: body.approval,
          attachments: body.attachments,
          assignee_id: body.assignee_id,
          assignee_ids: body.assignee_ids,
          id: data.id,
          itemheader_id_fk: body.itemheader_id_fk
        };

        const itemHeader = await sql.itemHeader.findOne({ where: { item_id_pk: body.itemheader_id_fk } });
        if (itemHeader) {
          await itemHeader.update({
            udf_freeform_01: body.status,
            lic_tracking_updated_date: new Date()
          });

          try {
            const itemIdentifier = String(itemHeader?.dataValues?.item_id_pk) || `ID ${body.itemheader_id_fk}`;
            const itemDescription = itemHeader?.dataValues?.item_descr_name || '';
            const itemNum = itemHeader?.dataValues?.item_num_id || '';
            await sendLicensingTeamsNotifications({
              payload: body,
              userInfo,
              itemIdentifier,
              itemDescription,
              itemNum
            });
          } catch (notifErr) {
            console.error("Failed to send Teams notifications:", notifErr);
          }
        }

        saved.push(mapData);
      } catch (itemErr) {
        console.error("Failed to add licensing status for item:", body.itemheader_id_fk, itemErr);
        failures.push({ index, itemheader_id_fk: body.itemheader_id_fk, status: body.status, message: itemErr.message || 'Failed to add licensing status' });
      }
    }

    // Surface partial/total failures instead of always returning a silent 200.
    if (failures.length) {
      const err = new Error(`${failures.length} of ${feedbackList.length} licensing status updates failed`);
      err.statusCode = saved.length ? 207 : 400;
      err.failures = failures;
      err.saved = saved;
      return result(err, null);
    }

    result(null, { statusCode: 200, data: saved });
  } catch (err) {
    result(null, err);
  }
};

