// L1: conservative licensing-status validation.
// Only rejects clearly-invalid values (empty/blank). Does NOT enforce
// allowed-transition ordering — those rules are not unambiguously expressed in
// existing backend code, so they are intentionally left to the frontend
// (feedback_dialog.component.ts onSelectFrom) until product confirms a state machine.
function validateLicensingStatus(status) {
  if (status === undefined || status === null) {
    return 'Status is required';
  }
  if (typeof status !== 'string') {
    return 'Status must be a string';
  }
  if (!status.trim()) {
    return 'Status cannot be empty';
  }
  return null;
}

// L1: rejects statuses that are not part of the known LicenseFeedBacks catalog
// (the same catalog the frontend status dropdown is populated from). This guards
// against arbitrary/unknown status values submitted outside the UI. Returns an
// error message string when the status is unknown, otherwise null. Fails open
// (returns null) if the catalog cannot be loaded, to avoid blocking valid saves.
async function validateKnownLicensingStatus(status) {
  try {
    const known = await sql.LicenseFeedBacks.findAll({ attributes: ['status'] });
    const allowed = new Set(
      (known || [])
        .map(row => (row.get ? row.get({ plain: true }) : row).status)
        .filter(Boolean)
        .map(s => String(s).trim().toLowerCase())
    );
    if (allowed.size === 0) return null; // catalog empty/unavailable -> fail open
    if (!allowed.has(String(status).trim().toLowerCase())) {
      return `Unknown licensing status: "${status}"`;
    }
    return null;
  } catch (err) {
    console.error('Could not validate licensing status against catalog:', err);
    return null; // fail open on lookup error
  }
}

