/**
 * L4: status POST failed after attachments were uploaded. Surface a clear
 * error and flag the orphaned attachment links (uploaded to storage but never
 * referenced by a saved status row). Minimal handling — no automatic rollback.
 */
private handleSaveFailure(attachmentsPayload: AttachmentPayload[]): void {
  const orphaned = (attachmentsPayload || []).filter(a => !!a.link);
  if (orphaned.length) {
    console.warn(
      '[FeedbackDialog] Status save failed after upload; orphaned attachments left in storage:',
      orphaned.map(a => a.link)
    );
    this._snakcbar.open(
      `Failed to save feedback. ${orphaned.length} uploaded file(s) may need cleanup.`,
      'close'
    );
  } else {
    this._snakcbar.open('Failed to save feedback', 'close');
  }
}

